    16→// SeaweedFSConfig represents SeaweedFS-specific configuration
    17→type SeaweedFSConfig struct {
    18→	Master      string `yaml:"master"`      // master server address (e.g., "localhost:9333")
    19→	Filer       string `yaml:"filer"`       // filer server address (e.g., "localhost:8888")
    20→	Collection  string `yaml:"collection"`  // collection name for artifacts
    21→	Replication string `yaml:"replication"` // replication strategy (e.g., "000" for dev, "001" for prod)
    22→	Timeout     int    `yaml:"timeout"`     // timeout in seconds
    23→	DataCenter  string `yaml:"datacenter"`  // data center identifier
