    40→// NewSeaweedFSClient creates a new SeaweedFS storage client
    41→func NewSeaweedFSClient(cfg SeaweedFSConfig) (*SeaweedFSClient, error) {
    42→	if cfg.Master == "" {
    43→		return nil, fmt.Errorf("seaweedfs master address is required")
    44→	}
    45→	if cfg.Filer == "" {
    46→		return nil, fmt.Errorf("seaweedfs filer address is required")
    47→	}
    48→
    49→	timeout := time.Duration(cfg.Timeout) * time.Second
    50→	if timeout == 0 {
    51→		timeout = 30 * time.Second
    52→	}
    53→
    54→	collection := cfg.Collection
    55→	if collection == "" {
    56→		collection = "artifacts"
    57→	}
    58→
    59→	replication := cfg.Replication
    60→	if replication == "" {
    61→		replication = "000" // no replication for dev environment
    62→	}
    63→
    64→	client := &SeaweedFSClient{
    65→		masterURL:   ensureHTTPScheme(cfg.Master),
    66→		filerURL:    ensureHTTPScheme(cfg.Filer),
    67→		collection:  collection,
    68→		replication: replication,
    69→		timeout:     timeout,
    70→		httpClient: &http.Client{
    71→			Timeout: timeout,
    72→		},
    73→	}
    74→
    75→	return client, nil
    76→}
