    87→func (c *SeaweedFSClient) PutObject(bucket, key string, body io.ReadSeeker, contentType string) (*PutObjectResult, error) {
    88→	fmt.Printf("[SeaweedFS PutObject] Starting upload - bucket: %s, key: %s, contentType: %s\n", bucket, key, contentType)
    89→
    90→	// Create directory structure in filer if needed
    91→	dir := filepath.Dir(key)
    92→	fmt.Printf("[SeaweedFS PutObject] Directory path: %s\n", dir)
    93→	if dir != "." && dir != "/" {
    94→		// For unified storage, the key already contains the full path including bucket
    95→		// So we don't need to add bucket prefix again
    96→		fmt.Printf("[SeaweedFS PutObject] Creating directory with full path: %s\n", dir)
    97→		if err := c.createDirectoryFullPath(dir); err != nil {
    98→			fmt.Printf("[SeaweedFS PutObject] ERROR: Failed to create directory %s: %v\n", dir, err)
    99→			return nil, fmt.Errorf("failed to create directory: %w", err)
   100→		}
   101→		fmt.Printf("[SeaweedFS PutObject] Directory created successfully\n")
   102→	}
   103→
   104→	// Use filer's direct upload endpoint which handles both volume upload and registration
   105→	// Note: We don't include collection parameter as it causes "context canceled" errors in SeaweedFS
   106→	// For unified storage, key already contains the full path including bucket
   107→	url := fmt.Sprintf("%s/%s?replication=%s", c.filerURL, key, c.replication)
   108→	fmt.Printf("[SeaweedFS PutObject] Upload URL: %s\n", url)
   109→
   110→	// Get file size for logging
   111→	fileSize := int64(0)
   112→	if size, err := body.Seek(0, 2); err == nil { // Seek to end to get size
   113→		fileSize = size
   114→	}
   115→	body.Seek(0, 0) // Reset to start for actual upload
   116→	fmt.Printf("[SeaweedFS PutObject] File size: %d bytes\n", fileSize)
   117→
   118→	// Create multipart form data
   119→	var buf bytes.Buffer
   120→	writer := multipart.NewWriter(&buf)
   121→
   122→	// Add file field
   123→	fileWriter, err := writer.CreateFormFile("file", filepath.Base(key))
   124→	if err != nil {
   125→		fmt.Printf("[SeaweedFS PutObject] ERROR: Failed to create form file: %v\n", err)
   126→		return nil, fmt.Errorf("failed to create form file: %w", err)
   127→	}
   128→
   129→	bytesWritten, err := io.Copy(fileWriter, body)
   130→	if err != nil {
   131→		fmt.Printf("[SeaweedFS PutObject] ERROR: Failed to copy file data: %v\n", err)
   132→		return nil, fmt.Errorf("failed to copy file data: %w", err)
   133→	}
   134→	fmt.Printf("[SeaweedFS PutObject] Copied %d bytes to multipart form\n", bytesWritten)
   135→
   136→	writer.Close()
   137→	fmt.Printf("[SeaweedFS PutObject] Multipart form size: %d bytes\n", buf.Len())
   138→
   139→	// Make the request
   140→	req, err := http.NewRequest("POST", url, &buf)
   141→	if err != nil {
   142→		fmt.Printf("[SeaweedFS PutObject] ERROR: Failed to create request: %v\n", err)
   143→		return nil, fmt.Errorf("failed to create request: %w", err)
   144→	}
   145→	req.Header.Set("Content-Type", writer.FormDataContentType())
   146→	fmt.Printf("[SeaweedFS PutObject] Request Content-Type: %s\n", writer.FormDataContentType())
   147→
   148→	fmt.Printf("[SeaweedFS PutObject] Executing HTTP POST request...\n")
   149→	resp, err := c.httpClient.Do(req)
   150→	if err != nil {
   151→		fmt.Printf("[SeaweedFS PutObject] ERROR: HTTP request failed: %v\n", err)
   152→		return nil, fmt.Errorf("failed to upload: %w", err)
   153→	}
   154→	defer resp.Body.Close()
   155→
   156→	fmt.Printf("[SeaweedFS PutObject] HTTP Response Status: %s (%d)\n", resp.Status, resp.StatusCode)
   157→
   158→	// Read response body for debugging
   159→	responseBody, _ := io.ReadAll(resp.Body)
   160→	fmt.Printf("[SeaweedFS PutObject] Response Body: %s\n", string(responseBody))
   161→
   162→	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
   163→		fmt.Printf("[SeaweedFS PutObject] ERROR: Upload failed with status %s, body: %s\n", resp.Status, string(responseBody))
   164→		return nil, fmt.Errorf("upload failed: %s", resp.Status)
   165→	}
   166→
   167→	// Parse response to get file info
   168→	var result struct {
   169→		Name string `json:"name"`
   170→		Size int64  `json:"size"`
   171→	}
   172→
   173→	// Reset response body reader since we already read it
   174→	responseReader := bytes.NewReader(responseBody)
   175→	if err := json.NewDecoder(responseReader).Decode(&result); err != nil {
   176→		fmt.Printf("[SeaweedFS PutObject] ERROR: Failed to parse response JSON: %v\n", err)
   177→		fmt.Printf("[SeaweedFS PutObject] Raw response: %s\n", string(responseBody))
   178→		return nil, fmt.Errorf("failed to parse response: %w", err)
   179→	}
   180→
   181→	fmt.Printf("[SeaweedFS PutObject] Upload successful - Name: %s, Size: %d\n", result.Name, result.Size)
   182→
   183→	return &PutObjectResult{
   184→		ETag:     "", // Not provided by filer direct upload
   185→		Location: fmt.Sprintf("%s/%s", bucket, key),
   186→		Size:     result.Size,
   187→	}, nil
   188→}
