   203→func (c *SeaweedFSClient) ListObjects(bucket, prefix string) ([]ObjectInfo, error) {
   204→	url := fmt.Sprintf("%s/%s/%s", c.filerURL, bucket, prefix)
   205→	req, err := http.NewRequest("GET", url, nil)
   206→	if err != nil {
   207→		return nil, err
   208→	}
   209→	req.Header.Set("Accept", "application/json")
   210→
   211→	resp, err := c.httpClient.Do(req)
   212→	if err != nil {
   213→		return nil, err
   214→	}
   215→	defer resp.Body.Close()
   216→
   217→	if resp.StatusCode == http.StatusNotFound {
   218→		// Directory doesn't exist yet, return empty list
   219→		return []ObjectInfo{}, nil
   220→	}
   221→	if resp.StatusCode != http.StatusOK {
   222→		return nil, fmt.Errorf("failed to list objects: %s", resp.Status)
   223→	}
   224→
   225→	var result struct {
   226→		Entries []struct {
   227→			FullPath string `json:"FullPath"`
   228→			FileSize int64  `json:"FileSize"`
   229→			Mode     int64  `json:"Mode"`
   230→			Mtime    string `json:"Mtime"`
   231→		} `json:"Entries"`
   232→	}
   233→
   234→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
   235→		return nil, fmt.Errorf("failed to decode response: %w", err)
   236→	}
   237→
   238→	var objects []ObjectInfo
   239→	for _, entry := range result.Entries {
   240→		// Extract just the name from the full path
   241→		name := filepath.Base(entry.FullPath)
   242→		// Include both files and directories for listing
   243→		objects = append(objects, ObjectInfo{
   244→			Key:          name,
   245→			Size:         entry.FileSize,
   246→			LastModified: entry.Mtime,
   247→			ContentType:  "application/octet-stream", // Default, SeaweedFS doesn't store this in listing
   248→		})
   249→	}
   250→
   251→	return objects, nil
   252→}
