   254→func (c *SeaweedFSClient) UploadArtifactBundle(keyPrefix, artifactPath string) error {
   255→	// Upload main artifact
   256→	if err := c.uploadFile(keyPrefix, artifactPath, "application/octet-stream"); err != nil {
   257→		return fmt.Errorf("failed to upload artifact %s: %w", artifactPath, err)
   258→	}
   259→
   260→	// Upload SBOM if exists
   261→	sbomPath := artifactPath + ".sbom.json"
   262→	if _, err := os.Stat(sbomPath); err == nil {
   263→		if err := c.uploadFile(keyPrefix, sbomPath, "application/json"); err != nil {
   264→			return fmt.Errorf("failed to upload SBOM %s: %w", sbomPath, err)
   265→		}
   266→	}
   267→
   268→	// Upload signature if exists
   269→	sigPath := artifactPath + ".sig"
   270→	if _, err := os.Stat(sigPath); err == nil {
   271→		if err := c.uploadFile(keyPrefix, sigPath, "application/octet-stream"); err != nil {
   272→			return fmt.Errorf("failed to upload signature %s: %w", sigPath, err)
   273→		}
   274→	}
   275→
   276→	// Upload certificate if exists (from keyless OIDC signing)
   277→	crtPath := artifactPath + ".crt"
   278→	if _, err := os.Stat(crtPath); err == nil {
   279→		if err := c.uploadFile(keyPrefix, crtPath, "application/x-pem-file"); err != nil {
   280→			return fmt.Errorf("failed to upload certificate %s: %w", crtPath, err)
   281→		}
   282→	}
   283→
   284→	return nil
   285→}
