   315→
   316→	resp, err := c.httpClient.Do(req)
   317→	if err != nil {
   318→		fmt.Printf("[SeaweedFS VerifyUpload] ERROR: HEAD request failed: %v\n", err)
   319→		return err
   320→	}
   321→	defer resp.Body.Close()
   322→
   323→	fmt.Printf("[SeaweedFS VerifyUpload] HEAD response status: %s (%d)\n", resp.Status, resp.StatusCode)
