   479→// registerInFiler registers an already uploaded file (by fileID) in the filer
   480→// This is used for advanced scenarios where files are uploaded directly to volume servers
   481→// and need to be registered in the filer separately. For normal use cases, use PutObject
   482→// which uses the filer's direct upload API that handles both upload and registration.
   483→func (c *SeaweedFSClient) registerInFiler(bucket, key, fileID, contentType string, size int64) error {
   484→	url := fmt.Sprintf("%s/%s/%s", c.filerURL, bucket, key)
   485→
   486→	// Create multipart form data with file metadata
   487→	var buf bytes.Buffer
   488→	writer := multipart.NewWriter(&buf)
   489→
   490→	// Add metadata fields
   491→	writer.WriteField("fid", fileID)
   492→	writer.WriteField("size", fmt.Sprintf("%d", size))
   493→	if contentType != "" {
   494→		writer.WriteField("mime", contentType)
   495→	}
   496→
   497→	writer.Close()
   498→
   499→	req, err := http.NewRequest("POST", url, &buf)
   500→	if err != nil {
   501→		return err
   502→	}
   503→	req.Header.Set("Content-Type", writer.FormDataContentType())
   504→
   505→	resp, err := c.httpClient.Do(req)
   506→	if err != nil {
   507→		return err
   508→	}
   509→	defer resp.Body.Close()
   510→
   511→	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
   512→		return fmt.Errorf("failed to register in filer: %s", resp.Status)
   513→	}
   514→
   515→	return nil
   516→}
