   518→func (c *SeaweedFSClient) uploadFile(keyPrefix, filePath, contentType string) error {
   519→	file, err := os.Open(filePath)
   520→	if err != nil {
   521→		return err
   522→	}
   523→	defer file.Close()
   524→
   525→	key := keyPrefix + filepath.Base(filePath)
   526→
   527→	// Retry upload up to 3 times
   528→	var lastErr error
   529→	for attempt := 1; attempt <= 3; attempt++ {
   530→		// Reset file pointer to beginning
   531→		if _, err := file.Seek(0, 0); err != nil {
   532→			return fmt.Errorf("failed to reset file pointer: %w", err)
   533→		}
   534→
   535→		result, err := c.PutObject(c.collection, key, file, contentType)
   536→		if err != nil {
   537→			lastErr = err
   538→			fmt.Printf("SeaweedFS upload attempt %d failed for %s: %v\n", attempt, key, err)
   539→			continue
   540→		}
   541→
   542→		// Verify upload by checking if we got a valid result with size
   543→		if result != nil && result.Size > 0 {
   544→			fmt.Printf("Successfully uploaded to SeaweedFS %s (size: %d bytes)\n", key, result.Size)
   545→			return nil
   546→		}
   547→
   548→		lastErr = fmt.Errorf("upload completed but no valid result received")
   549→	}
   550→
   551→	return fmt.Errorf("failed to upload after 3 attempts: %w", lastErr)
   552→}
